import React from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
// Import your theme context here
// import { useTheme } from '../context/ThemeContext'; 
import { Activity, Archive, LayoutDashboard, LogOut, Cpu, Sun, Moon } from 'lucide-react';

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  
  // Mocking theme state - Replace with your actual theme hook
  const [isDark, setIsDark] = React.useState(true); 

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const isActive = (path) => location.pathname === path;

  return (
    <nav style={navWrapper}>
      {/* ── Brand Section ── */}
      <Link to="/" style={brandLink}>
        <Cpu size={28} color="var(--accent-primary)" />
        <span style={brandText}>FINIFY_AI</span>
      </Link>

      {/* ── Navigation Links ── */}
      <div style={navLinks}>
        <Link to="/generate" style={linkStyle(isActive('/generate'))}>
          <LayoutDashboard size={20} /> GENERATE
        </Link>
        <Link to="/vault" style={linkStyle(isActive('/vault'))}>
          <Archive size={20} /> VAULT
        </Link>
        <Link to="/live" style={linkStyle(isActive('/live'))}>
          <Activity size={20} /> LIVE_PULSE
        </Link>
      </div>

      {/* ── Actions Section ── */}
      <div style={userSection}>
        {/* THEME TOGGLE SWITCH */}
        <button 
          onClick={() => setIsDark(!isDark)} 
          style={themeToggleBtn(isDark)}
          title="Toggle System Luminescence"
        >
          {isDark ? <Moon size={20} /> : <Sun size={20} />}
          <span style={toggleText}>{isDark ? 'DARK_MODE' : 'LIGHT_MODE'}</span>
        </button>

        {user ? (
          <>
            <div style={userInfo}>
              <span style={userLabel}>SESSION_OPERATOR</span>
              <span style={userName}>{user.full_name?.toUpperCase()}</span>
            </div>
            <button onClick={handleLogout} style={logoutBtn}>
              <LogOut size={22} />
            </button>
          </>
        ) : (
          <Link to="/login" style={loginBtn}>INITIALIZE_CORE</Link>
        )}
      </div>
    </nav>
  );
};

/* --- Visual Styles --- */
const navWrapper = {
  width: '100%',
  height: '80px',
  background: 'var(--nav-bg, #0a0b0e)', // Uses CSS variable if available
  borderBottom: '2px solid var(--surface-border, #1a1d23)',
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  padding: '0 2.5rem',
  boxSizing: 'border-box',
  position: 'sticky',
  top: 0,
  zIndex: 1000,
};

const brandLink = { display: 'flex', alignItems: 'center', gap: '15px', textDecoration: 'none' };
const brandText = { fontSize: '1.4rem', fontWeight: 900, color: 'var(--text-primary, #fff)', letterSpacing: '0.2em', fontFamily: 'monospace' };

const navLinks = { display: 'flex', gap: '3rem', alignItems: 'center' };
const linkStyle = (active) => ({
  textDecoration: 'none',
  color: active ? 'var(--accent-primary)' : '#666',
  fontSize: '0.9rem',
  fontWeight: 900,
  letterSpacing: '0.15em',
  display: 'flex',
  alignItems: 'center',
  gap: '10px',
  fontFamily: 'monospace',
  borderBottom: active ? '2px solid var(--accent-primary)' : '2px solid transparent',
  padding: '8px 0'
});

const userSection = { display: 'flex', alignItems: 'center', gap: '25px' };

const themeToggleBtn = (isDark) => ({
  background: 'none',
  border: `1px solid ${isDark ? '#333' : 'var(--accent-primary)'}`,
  borderRadius: '8px',
  color: isDark ? '#666' : 'var(--accent-primary)',
  cursor: 'pointer',
  display: 'flex',
  alignItems: 'center',
  gap: '10px',
  padding: '8px 12px',
  transition: 'all 0.3s ease',
});

const toggleText = { fontSize: '0.65rem', fontWeight: 900, fontFamily: 'monospace', letterSpacing: '0.1em' };

const userInfo = { display: 'flex', flexDirection: 'column', alignItems: 'flex-end' };
const userLabel = { fontSize: '0.6rem', color: 'var(--accent-primary)', fontWeight: 900, letterSpacing: '0.15em' };
const userName = { fontSize: '1rem', color: 'var(--text-primary, #fff)', fontWeight: 700, fontFamily: 'monospace' };

const logoutBtn = {
  background: 'rgba(239, 68, 68, 0.1)',
  border: '1px solid rgba(239, 68, 68, 0.3)',
  color: '#ef4444',
  padding: '10px',
  borderRadius: '10px',
  cursor: 'pointer',
};

const loginBtn = {
  background: 'var(--accent-primary)',
  color: '#000',
  padding: '10px 20px',
  borderRadius: '8px',
  textDecoration: 'none',
  fontSize: '0.85rem',
  fontWeight: 900,
  fontFamily: 'monospace'
};

export default Navbar;
